class QRScanner {
    constructor(videoElement, onDecode) {
        this.video = videoElement;
        this.onDecode = onDecode;

        this.canvas = document.createElement("canvas");
        this.ctx = this.canvas.getContext("2d", { willReadFrequently: true });

        this.isRunning = false;
        this.isWorkerBusy = false;

        this.worker = new Worker("./qr-scanner-worker.min.js");

        this.worker.onmessage = (event) => {
            this.isWorkerBusy = false;

            if (!event.data) return;

            if (typeof event.data === "object" && event.data.error) {
                console.error("Worker error:", event.data.error);
                return;
            }

            this.onDecode(event.data);
        };

        this.worker.onerror = (err) => {
            this.isWorkerBusy = false;
            console.error("Worker failed:", err);
        };
    }

    async start() {
        try {
            this.stream = await navigator.mediaDevices.getUserMedia({
                video: {
                    facingMode: { ideal: "environment" },
                    width: { ideal: 1280 },
                    height: { ideal: 720 }
                },
                audio: false
            });

            this.video.srcObject = this.stream;
            this.video.setAttribute("playsinline", true);
            this.video.setAttribute("autoplay", true);
            this.video.setAttribute("muted", true);

            await new Promise((resolve) => {
                this.video.onloadedmetadata = () => resolve();
            });

            await this.video.play();

            this.isRunning = true;
            this.scanLoop();
        } catch (err) {
            console.error("Camera start error:", err);
            throw err;
        }
    }

    stop() {
        this.isRunning = false;

        if (this.stream) {
            this.stream.getTracks().forEach(track => track.stop());
            this.stream = null;
        }
    }

    scanLoop() {
        if (!this.isRunning) return;

        if (
            this.video.readyState === this.video.HAVE_ENOUGH_DATA &&
            !this.isWorkerBusy
        ) {
            const vw = this.video.videoWidth;
            const vh = this.video.videoHeight;

            if (vw > 0 && vh > 0) {
                // کوچک‌تر کردن فریم برای سرعت بهتر
                const targetWidth = 800;
                const scale = targetWidth / vw;
                const targetHeight = Math.floor(vh * scale);

                this.canvas.width = targetWidth;
                this.canvas.height = targetHeight;

                this.ctx.drawImage(this.video, 0, 0, targetWidth, targetHeight);

                const imageData = this.ctx.getImageData(0, 0, targetWidth, targetHeight);

                this.isWorkerBusy = true;
                this.worker.postMessage(imageData);
            }
        }

        requestAnimationFrame(() => this.scanLoop());
    }
}
